def build(ex):
    # CoNaLa mined-curated: NL intent -> Python code snippet (CodeBLEU-scored).
    # rewritten_intent is often null in mined data; fall back to raw `intent`.
    intent = ex.get("rewritten_intent") or ex.get("intent")
    code = ex.get("snippet")
    if not intent or not str(intent).strip():
        return None
    if not code or not str(code).strip():
        return None
    return {"prompt": str(intent).strip(), "query": None, "response": str(code).strip()}

